if ('scrollRestoration' in history) {
    history.scrollRestoration = 'manual';
}

function getValueURLSearchParamByName(name) {
    const urlParams = new URLSearchParams(window.location.search);
    const value = urlParams.get(name);
    return value;
}

function updateURLSearchParamByName(name, value) {
    const params = new URLSearchParams(window.location.search);
    params.set(name, value);

    const newUrl = `${window.location.pathname}?${params.toString()}`;
    window.history.replaceState(null, '', newUrl);
}

function getSubPathByIndex(index) {
    const path = window.location.pathname;
    const subUrls = path.split('/');
    if (subUrls && subUrls.length > index) {
        return subUrls[index];
    }
}

function updateSubPathByIndex(index, value, keepSubPath = false) {
    let path = window.location.pathname;
    let parts = path.split('/').filter(p => p !== '');

    if (index < 0 || index >= parts.length) {
        return;
    }
    
    parts[index] = value;
    
    if (!keepSubPath) {
        parts = parts.slice(0, index + 1);
    }
    
    const newPath = '/' + parts.join('/');
    
    window.history.replaceState(null, '', newPath);
}

function scrollToViewByTab() {
    let subPath = getSubPathByIndex(2);
    let height = $(window).width() < 992 ? 88 : 80;

    let containerId = $(`#nav-header-container .nav-item[data-path="${subPath}"]`).data("id");
    let targetElement = $(`#${containerId}`);

    if (subPath && targetElement.length > 0) {
        let interval = setInterval(() => {
            if (targetElement.is(":visible")) {
                $(window).scrollTop(targetElement.offset().top - height);
                clearInterval(interval);
            }
        }, 200);
    }
}

function handleToggleMacroSidebar(containerName, callbackOpen, callbackClose) {
    let $container = $(containerName);
    if ($container && $container.length > 0) {
        let $macroSidebarBox = $container.find(".macro-sidebar");
        let $macroToggleBox = $container.find(".macro-sidebar__toggle-box");
        if ($macroSidebarBox && $macroSidebarBox.length > 0) {
            let sidebarHeight = $macroSidebarBox.outerHeight();
            if ($macroSidebarBox.hasClass("macro-sidebar--hidden")) {
                $macroSidebarBox.removeClass("macro-sidebar--hidden");
                $macroToggleBox.removeClass("toggle-box--collapse").addClass("toggle-box--expand");
                setTimeout(() => {
                    $macroSidebarBox.css("max-height", `unset`);
                }, 600);
                if (callbackOpen && typeof callbackOpen === 'function') {
                    callbackOpen();
                }
            } else {
                $macroSidebarBox.css("max-height", `${sidebarHeight}px`);
                $macroSidebarBox.addClass("macro-sidebar--hidden");
                $macroToggleBox.removeClass("toggle-box--expand").addClass("toggle-box--collapse");
                if (callbackClose && typeof callbackClose === 'function') {
                    callbackClose();
                }
            }
        }
    }
}

function handleToggleVertMacroSidebar(e) {
    let $this = $(e.currentTarget);
    let $wrapper = $this.closest(".macro-sidebar__toggle-wrapper");
    if ($wrapper && $wrapper.length > 0) {
        let $sidebar = $wrapper.find(".macro-sidebar");
        let $collapseBox = $wrapper.find(".macro-sidebar__collapse-box");
        if ($sidebar.hasClass("macro-sidebar--show")) {
            $sidebar.removeClass("macro-sidebar--show");
            $collapseBox.removeClass("collapse-box--expand");
        } else {
            $sidebar.addClass("macro-sidebar--show");
            $collapseBox.addClass("collapse-box--expand");
        }
    }
}


function handleNavHeader() {
    var $navHeader = $('#nav-header-container');
    var $navItems = $('#nav-header-container .nav-item');
    var screenWidth = vst.pageWidth();
    var menuHeight = 0;
    $(document).scroll(function () {
        var scrollTop = $(window).scrollTop();
        if ((screenWidth >= 768 && scrollTop > 200) || (screenWidth < 768 && scrollTop > 120)) {
            $navHeader.addClass('nav-header-container--show');
            menuHeight = 38 + 90;
            $navItems.each(function () {
                var dataId = $(this).data("id");
                let $element = $("#" + dataId);
                if ($element.length) {
                    var elementPos = $element.offset().top;
                    var elementHeight = $element.height();
                    if (scrollTop >= (elementPos - menuHeight) && scrollTop < (elementPos + elementHeight + - menuHeight)) {
                        if (!$(this).hasClass("nav-item--active")) {
                            $(this).addClass("nav-item--active");
                            $("#nav-header-container").animate({
                                scrollLeft: $("#nav-header-container").scrollLeft() + $("#nav-header-container .nav-item--active").offset().left
                            }, 250);
                        }
                    } else {
                        $(this).removeClass("nav-item--active");
                    }
                }

            });
        }
        else {
            $navHeader.removeClass('nav-header-container--show');
            $navItems.removeClass("nav-item--active");
            menuHeight = 0;
        }
    });

    scrollToViewByTab();

    $navItems.click(function (event) {
        let dataPath = $(this).data("path");
        if (dataPath) {
            event.preventDefault();
            updateSubPathByIndex(1, dataPath, dataPath === "du-lieu");
            scrollToViewByTab();
        }
    });
}

$(document).ready(function () {
    handleNavHeader();

    $("#chart-detail-list-view--js").addClass("macro-table-wrapper");
    $("#click-fullscreen--el").click(function () {
        if ($(this).hasClass("active")) {
            $("#chart-detail-list-view--js").css("overflow", "");
            $("#chart-detail-list-view--js").addClass("macro-table-wrapper");
        } else {
            $("#chart-detail-list-view--js").css("overflow", "auto");
            $("#chart-detail-list-view--js").removeClass("macro-table-wrapper");
        }
    })
});

window.onload = function () {
    scrollToViewByTab();
};

const macro = {};
((global) => {
    function getArrowClassForCustomTooltip(tooltip, element) {
        var tooltipPos = tooltip.offset();
        var elementPos = element.offset();

        var tooltipRect = {
            left: tooltipPos.left,
            top: tooltipPos.top,
            right: tooltipPos.left + tooltip.outerWidth(),
            bottom: tooltipPos.top + tooltip.outerHeight(),
            centerX: tooltipPos.left + tooltip.outerWidth() / 2,
            centerY: tooltipPos.top + tooltip.outerHeight() / 2,
            width: tooltip.outerWidth(),
            height: tooltip.outerHeight()
        };

        var elementRect = {
            left: elementPos.left,
            top: elementPos.top,
            right: elementPos.left + element.outerWidth(),
            bottom: elementPos.top + element.outerHeight(),
            centerX: elementPos.left + element.outerWidth() / 2,
            centerY: elementPos.top + element.outerHeight() / 2,
            width: element.outerWidth(),
            height: element.outerHeight()
        };

        // Check tooltip position relative to element
        var isAbove = tooltipRect.bottom <= elementRect.top;
        var isBelow = tooltipRect.top >= elementRect.bottom;
        var isLeft = tooltipRect.right <= elementRect.left;
        var isRight = tooltipRect.left >= elementRect.right;

        var arrowPosition = {
            class: '',
            offsetX: 0,
            offsetY: 0
        };

        const arrowMargin = 20;
        if (isAbove) {
            arrowPosition.class = 'tooltip-top';
            arrowPosition.offsetX = Math.max(arrowMargin, Math.min(tooltipRect.width - arrowMargin, elementRect.centerX - tooltipRect.left));
        } else if (isBelow) {
            arrowPosition.class = 'tooltip-bottom';
            arrowPosition.offsetX = Math.max(arrowMargin, Math.min(tooltipRect.width - arrowMargin, elementRect.centerX - tooltipRect.left));
        } else if (isLeft) {
            arrowPosition.class = 'tooltip-left';
            arrowPosition.offsetY = Math.max(arrowMargin, Math.min(tooltipRect.height - arrowMargin, elementRect.centerY - tooltipRect.top));
        } else if (isRight) {
            arrowPosition.class = 'tooltip-right';
            arrowPosition.offsetY = Math.max(arrowMargin, Math.min(tooltipRect.height - arrowMargin, elementRect.centerY - tooltipRect.top));
        } else {
            // Fallback for overlapping cases
            var dx = tooltipRect.centerX - elementRect.centerX;
            var dy = tooltipRect.centerY - elementRect.centerY;

            if (Math.abs(dx) > Math.abs(dy)) {
                if (dx > 0) {
                    arrowPosition.class = 'tooltip-right';
                    arrowPosition.offsetY = Math.max(12, Math.min(tooltipRect.height - 12, elementRect.centerY - tooltipRect.top));
                } else {
                    arrowPosition.class = 'tooltip-left';
                    arrowPosition.offsetY = Math.max(12, Math.min(tooltipRect.height - 12, elementRect.centerY - tooltipRect.top));
                }
            } else {
                if (dy > 0) {
                    arrowPosition.class = 'tooltip-bottom';
                    arrowPosition.offsetX = Math.max(12, Math.min(tooltipRect.width - 12, elementRect.centerX - tooltipRect.left));
                } else {
                    arrowPosition.class = 'tooltip-top';
                    arrowPosition.offsetX = Math.max(12, Math.min(tooltipRect.width - 12, elementRect.centerX - tooltipRect.left));
                }
            }
        }

        return arrowPosition;
    }

    function handleCustomTooltipByElement(elementSelectors) {
        $(elementSelectors).tooltip({
            content: function () {
                return $(this).attr('title');
            },
            tooltipClass: "custom-tooltip__tips",
            position: {
                my: "left bottom-8",
                at: "left top",
                collision: "flipfit flip"
            },
            open: function (event, ui) {
                var element = $(this);
                var tooltip = ui.tooltip;

                tooltip.removeClass('tooltip-top tooltip-bottom tooltip-left tooltip-right tooltip-top-left tooltip-top-right tooltip-bottom-left tooltip-bottom-right');

                setTimeout(function () {
                    var arrowData = getArrowClassForCustomTooltip(tooltip, element);
                    tooltip.addClass(arrowData.class);

                    // Apply dynamic positioning
                    var styles = '';

                    if (arrowData.class === 'tooltip-top' || arrowData.class === 'tooltip-bottom') {
                        styles = 'left: ' + arrowData.offsetX + 'px !important; transform: none !important;';
                    } else if (arrowData.class === 'tooltip-left' || arrowData.class === 'tooltip-right') {
                        styles = 'top: ' + arrowData.offsetY + 'px !important; transform: none !important;';
                    }

                    // Create dynamic style for this tooltip
                    if (styles) {
                        var styleId = 'tooltip-arrow-style-' + Math.random().toString(36).substr(2, 9);
                        var styleElement = document.createElement('style');
                        styleElement.id = styleId;
                        styleElement.innerHTML = '.ui-tooltip.' + arrowData.class + ':after { ' + styles + ' }';
                        document.head.appendChild(styleElement);

                        tooltip.data('arrow-style-id', styleId);
                    }
                }, 50);
            }
        });
    }

    function getElementPosition(element) {
        const rect = element.getBoundingClientRect();
        return {
            x: rect.left + window.scrollX,
            y: rect.top + window.scrollY,
            width: rect.width,
            height: rect.height
        };
    }

    function getPositioningContext(element) {
        let parent = element.parentElement;
        while (parent && parent !== document.body) {
            const style = window.getComputedStyle(parent);
            if (style.position === 'relative' ||
                style.position === 'absolute' ||
                style.position === 'fixed') {
                return parent;
            }
            parent = parent.parentElement;
        }
        return document.body;
    }

    function calculateRelativePosition(targetElement, referenceElement) {
        // Get absolute positions
        const targetPos = getElementPosition(targetElement);
        const refPos = getElementPosition(referenceElement);

        // Find the positioning context for the target element
        const context = getPositioningContext(targetElement);
        const contextPos = getElementPosition(context);

        // Calculate position relative to the positioning context
        const relativeToContext = {
            x: refPos.x - contextPos.x,
            y: refPos.y - contextPos.y
        };

        return {
            absolute: {
                target: targetPos,
                reference: refPos
            },
            relative: relativeToContext,
            context: context.className || 'body',
            contextPos: contextPos
        };
    }

    function showPopupLogin() {
        $("#login-form").modal('show');
    }
    function getLimitDateFromObjPattern({ days, months, years }) {
        if ((days == null && months == null && years == null) || (days == "" && months == "" && years == "")) {
            const minDate = new Date(1900, 0, 1);
            minDate.setHours(0, 0, 0, 0);
            return minDate;
        }

        const limitDate = new Date().addDays(-days).addMonths(-months).addYears(-years);
        limitDate.setHours(0, 0, 0, 0);

        return limitDate;
    }
    function checkMacroPermission(listPermission, packageUserCurrent, { menuId_RegEx, value = "true", isLimitData, date }) {
        if (!isLogined) {
            showPopupLogin();
            return false;
        }

        const regex = new RegExp(menuId_RegEx);
        let filterPermission = listPermission.filter(item => regex.test(item.MenuId));
        if (isLimitData) {
            if (!filterPermission || filterPermission.length === 0) {
                return true;
            }
            let objTime = filterPermission[0].Value ? JSON.parse(filterPermission[0].Value) : { };
            let limitDate = getLimitDateFromObjPattern(objTime);
            let dateCompare = date.setHours(0, 0, 0, 0);

            if (dateCompare < limitDate) {
                ShowPopupRequestUpgradeAccount(packageUserCurrent, true);
                return false;
            }
        } else {
            let isPermission = filterPermission.some(item => item.Value == value);
            if (!isPermission) {
                ShowPopupRequestUpgradeAccount(packageUserCurrent, false);
                return false;
            }
        }
        return true;
    }

    function calculateRemainingSpace(containerSelector, elementSelector) {
        const $container = $(containerSelector);
        const $element = $(elementSelector);

        // Kiểm tra element tồn tại
        if (!$container.length || !$element.length) {
            console.error('Container or element not existed');
            return null;
        }

        // Lấy width của container và padding một lần
        const containerWidth = $container.width();
        const containerPadding = parseFloat($container.css('padding-left')) +
            parseFloat($container.css('padding-right'));

        const $items = $container.children(':visible');
        const gap = parseInt($container.css('column-gap')) || 0;
        const totalGap = ($items.length - 1) * gap;

        // Lấy width hiện tại của element
        //const currentElementWidth = $element.outerWidth(true);
        let currentElementWidth = $element.children(':visible')
            .toArray()
            .reduce((total, el) => total + $(el).outerWidth(true), 0);

        const $elementItems = $element.children(':visible');
        const elementGap = parseInt($element.css('column-gap')) || 0;
        const elementTotalGap = ($elementItems.length - 1) * elementGap;
        currentElementWidth += elementTotalGap;

        // Tính tổng width của các phần tử khác (có display !== none)
        const otherElementsWidth = $container.children()
            .not(elementSelector)
            .filter(':visible')
            .toArray()
            .reduce((total, el) => total + $(el).outerWidth(true), 0);

        // Tính không gian khả dụng
        const availableSpace = containerWidth - otherElementsWidth - totalGap;
        const maxPossibleWidth = Math.max(0, availableSpace); // Đảm bảo không âm

        return {
            currentWidth: currentElementWidth,
            maxWidth: maxPossibleWidth,
            remainingSpace: maxPossibleWidth - currentElementWidth,
            containerWidth: containerWidth,
            otherElementsWidth: otherElementsWidth,
            containerPadding: containerPadding
        };
    }

    global.customTooltip = handleCustomTooltipByElement;
    global.calculateRelativePosition = calculateRelativePosition;
    global.checkPermission = checkMacroPermission;
    global.calculateRemainingSpace = calculateRemainingSpace;
})(macro);

(function () {
    function handleThemeMode() {
        let storeThemeName = localStorage.getItem("darkModetheme");
        storeThemeName = storeThemeName ? storeThemeName : "light";
        let classTheme, classThemeOld;
        let urlLogoDarkMode = "https://image.vietstock.vn/common/logoVSTF_darkmode.svg";
        let urlLogoLightMode = "https://image.vietstock.vn/common/logoVSTF.svg";
        let urlLogoOld, urlLogoNew;
        if (storeThemeName === "dark") {
            classTheme = "theme-dark";
            classThemeOld = "theme-light";
            urlLogoOld = urlLogoLightMode;
            urlLogoNew = urlLogoDarkMode;

            $("#irAwardsDark").css({ "display": "block" });
            $("#irAwards").css({ "display": "none" });
        } else {
            classTheme = "theme-light";
            classThemeOld = "theme-dark";
            urlLogoOld = urlLogoDarkMode;
            urlLogoNew = urlLogoLightMode;

            $("#irAwardsDark").css({ "display": "none" });
            $("#irAwards").css({ "display": "block" });
        }
        $(".js-option-theme-mode").attr("data-mode", storeThemeName);
        $("html").addClass(classTheme).removeClass(classThemeOld);

        document.querySelectorAll('img').forEach(img => {
            img.src = img.src.replace(urlLogoOld, urlLogoNew);
        });

        let isDarkTheme = (storeThemeName === "dark");
        const eventData = {
            ThemeName: storeThemeName,
            IsDarkTheme: isDarkTheme
        };
        $(document).trigger("changeThemeMode", eventData);

        updateChartStyle(isDarkTheme);
    }

    function updateChartStyle(isDarkTheme) {
        if (macro.chart_data) {
            macro.chart_data.update({
                legend: {
                    itemStyle: {
                        color: isDarkTheme ? "#999" : "#666",
                    },
                    itemHiddenStyle: {
                        color: isDarkTheme ? "rgba(153, 153, 153, 0.5)" : "rgba(102, 102, 102, 0.5)"
                    }
                },
                tooltip: {
                    backgroundColor: isDarkTheme ? "#2e2e2e" : "#fff",
                    style: {
                        color: isDarkTheme ? "#ccc" : "#282828"
                    }
                }
            });

            macro.chart_data.yAxis.forEach(axis => {
                axis.update({
                    gridLineColor: isDarkTheme ? '#ffffff26' : '#eee',
                    labels: {
                        style: {
                            color: isDarkTheme ? "#999" : "#666"
                        }
                    }
                });
            });

            macro.chart_data.xAxis[0].update({
                tickColor: (isDarkTheme ? "#999" : "#00000026"),
                lineColor: (isDarkTheme ? "#999" : "#00000026"),
                labels: {
                    style: {
                        color: isDarkTheme ? "#999" : "#666"
                    }
                }
            });
        }
    }

    function initThemeMode() {
        handleThemeMode();
    }

    $(".js-option-theme-mode").on("click", function () {
        let storeThemeName = localStorage.getItem("darkModetheme");
        let isDarkTheme = (storeThemeName === "dark");
        if (isDarkTheme) {
            storeThemeName = "light";
        } else {
            storeThemeName = "dark";
        }

        localStorage.setItem("darkModetheme", storeThemeName);
        handleThemeMode();
    });

    function init() {
        initThemeMode();
    }

    init();
})();;

